import{_ as a}from"./chunks/gazebo.DmHT6Ixn.js";import{_ as s,c as e,o as t,a4 as h}from"./chunks/framework.BxjRYGQi.js";const b=JSON.parse('{"title":"在Gazebo中仿真机器人","description":"","frontmatter":{},"headers":[],"relativePath":"zh/02-quick-start/02-Gazebo_Simulation.md","filePath":"zh/02-quick-start/02-Gazebo_Simulation.md"}'),l={name:"zh/02-quick-start/02-Gazebo_Simulation.md"};function n(o,i,k,r,p,d){return t(),e("div",{"data-pagefind-body":!0},i[0]||(i[0]=[h('<h1 id="在gazebo中仿真机器人" tabindex="-1">在 Gazebo 中仿真机器人 <a class="header-anchor" href="#在gazebo中仿真机器人" aria-label="Permalink to “在Gazebo中仿真机器人”">​</a></h1><p>本章节介绍如何在 Gazebo 中模拟捷勃特机器人 ——Gazebo 是一款高度可扩展的 3D 机器人仿真器，支持多物理引擎（ODE、Bullet、DART）、丰富的传感器插件（LiDAR、深度相机、IMU、GPS），并通过 gazebo_ros_pkgs 与 ROS 2 实现深度集成。Gazebo 可让您在真实感虚拟环境中安全地测试和优化算法，然后再部署到真实硬件上。</p><h2 id="" tabindex="-1"><img src="'+a+'" alt=""> <a class="header-anchor" href="#" aria-label="Permalink to “”">​</a></h2><p>为了在 Gazebo 中模拟捷勃特机器人，请使用以下命令：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_gazebo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gazebo_demo.launch.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> robot_name:={机器人型号}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> controller_name:={控制器名称}</span></span></code></pre></div><p>例如，启动 C5A 型号的 Gazebo 仿真：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ros2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gbt_gazebo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gazebo_demo.launch.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> robot_name:=C5A</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> controller_name:=gbt_c5a_arm_controller</span></span></code></pre></div><p>这将打开 Gazebo，并加载相应的机器人模型和环境设置。</p><blockquote><p>控制器名称通常为 <code>gbt_{机器人型号}_arm_controller</code> ，具体名称请参考 <code>gbt_moveit</code> 包对应机器人的控制器配置文件。</p><p>比如： <code>gbt_moveit_config/c5a_moveit_config/config/ros2_controllers.yaml</code></p></blockquote><h2 id="配置与自定义" tabindex="-1">配置与自定义 <a class="header-anchor" href="#配置与自定义" aria-label="Permalink to “配置与自定义”">​</a></h2><p>可以通过修改 <code>config</code> 目录中的文件来自定义 Gazebo 仿真环境，包括调整物理参数、添加或删除对象等。</p><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><p>若 gazebo 没有正常关闭，请使用以下命令关闭 gazebo：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">kill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -9</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aux</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;[g]azebo&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> awk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{print $2}&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div>',14)]))}const F=s(l,[["render",n]]);export{b as __pageData,F as default};
